describe("Temporal.Duration",()=>{describe("creation and parsing",()=>{it("can be created from an object",()=>{let e=Temporal.Duration.from({hours:3,minutes:30});expect(e.hours).toBe(3),expect(e.minutes).toBe(30),expect(e.toString()).toBe("PT3H30M")}),it("can be parsed from an ISO 8601 string",()=>{let e=Temporal.Duration.from("P1Y2M3DT4H5M6.007008009S");expect(e.years).toBe(1),expect(e.months).toBe(2),expect(e.days).toBe(3),expect(e.hours).toBe(4),expect(e.minutes).toBe(5),expect(e.seconds).toBe(6),expect(e.milliseconds).toBe(7),expect(e.microseconds).toBe(8),expect(e.nanoseconds).toBe(9)}),it("can be created from an own object",()=>{let e=Temporal.Duration.from("PT0S"),o=Temporal.Duration.from(e);expect(e).toEqual(o)}),it("has a blank property that detects zero durations",()=>{let e=Temporal.Duration.from("PT0S");expect(e.blank).toBe(!0);let o=Temporal.Duration.from({seconds:1});expect(o.blank).toBe(!1)})}),describe("arithmetic methods",()=>{let e=Temporal.Duration.from({hours:1,minutes:30}),o=Temporal.Duration.from({minutes:45});it("abs() and negated() returns durations correctly",()=>{let t=e.negated();expect(t.hours).toBe(-1),expect(t.abs().hours).toBe(1)}),it("add() return durations correctly",()=>{let t=e.add(o);expect(t.hours).toBe(2),expect(t.minutes).toBe(15)}),it("compare() works correctly",()=>{expect(Temporal.Duration.compare(e,o)).toBe(1),expect(Temporal.Duration.compare(o,e)).toBe(-1),expect(Temporal.Duration.compare(e,e)).toBe(0)}),it("subtract() return durations correctly",()=>{let t=e.subtract(o);expect(t.hours).toBe(0),expect(t.minutes).toBe(45)}),it("toJSON() returns the ISO string",()=>{let t=Temporal.Duration.from({days:40});expect(JSON.stringify(t)).toBe('"P40D"')}),it("valueOf() throws a TypeError",()=>{let t=Temporal.Duration.from({seconds:1});expect(()=>{+t}).toThrow()}),it("with() returns a new duration with updated fields",()=>{let r=Temporal.Duration.from({hours:1,minutes:30}).with({minutes:45});expect(r.hours).toBe(1),expect(r.minutes).toBe(45)})}),describe("properties",()=>{it("should have correct property values for weeks and all components",()=>{let e=Temporal.Duration.from({weeks:2,days:3,hours:5});expect(e.weeks).toBe(2),expect(e.days).toBe(3),expect(e.hours).toBe(5)}),it("should report the correct sign for durations",()=>{let e=Temporal.Duration.from({hours:5});expect(e.sign).toBe(1);let o=e.negated();expect(o.sign).toBe(-1);let t=Temporal.Duration.from("PT0S");expect(t.sign).toBe(0)}),it("has correct toStringTag",()=>{let e=Temporal.Duration.from("PT0S");expect(Object.prototype.toString.call(e)).toBe("[object Temporal.Duration]")})})});
